// Store sensor data by topic (skip timer messages)
if (msg.topic && msg.topic !== "timer" && msg.payload !== undefined) {
    flow.set("sensor_" + msg.topic, msg.payload);
}

// Read config
const soc = flow.get("sensor_soc") || 0;
const voltage = flow.get("sensor_batt_voltage") || 0;
const voltageThresholdLow = flow.get("voltage_threshold_low") || 48.0;

// Shore config
const shoreEnabled = flow.get("shore_enabled") || false;
const thresholdLow = flow.get("threshold_low") || 40;
const thresholdHigh = flow.get("threshold_high") || 60;
let shoreState = flow.get("state") || "SHORE_OFF";
const lastShoreChange = flow.get("last_state_change") || 0;

// Charger config
const chargerEnabled = flow.get("charger_enabled") || false;
const chargerEnableSoc = flow.get("charger_enable_soc") || 25;
const chargerDisableSoc = flow.get("charger_disable_soc") || 45;
let chargerState = flow.get("charger_state") || "CHARGER_ON";
const lastChargerChange = flow.get("last_charger_change") || 0;

const now = Date.now();

// Collect dashboard data (always sent)
const acOutL1 = flow.get("sensor_ac_out_l1") || 0;
const acOutL2 = flow.get("sensor_ac_out_l2") || 0;
const mpptPower = flow.get("sensor_mppt_power") || 0;
const batteryCurrent = flow.get("sensor_batt_current") || 0;
const shoreInL1 = flow.get("sensor_shore_in_l1") || 0;
const shoreInL2 = flow.get("sensor_shore_in_l2") || 0;
const battTempC = flow.get("sensor_batt_temp");
const battTempF = battTempC != null ? Math.round(battTempC * 9/5 + 32) : null;

const dashboard = {
    state: shoreEnabled ? shoreState : "MANUAL",
    chargerState: chargerEnabled ? chargerState : "MANUAL",
    soc,
    shoreEnabled,
    chargerEnabled,
    thresholdLow,
    thresholdHigh,
    chargerEnableSoc,
    chargerDisableSoc,
    acOutL1,
    acOutL2,
    acTotal: acOutL1 + acOutL2,
    mpptPower,
    batteryCurrent,
    shorePower: shoreInL1 + shoreInL2,
    shoreInL1,
    shoreInL2,
    battTempF,
    voltage,
    voltageThresholdLow,
    connectReason: flow.get("connect_reason") || null,
    chargerConnectReason: flow.get("charger_connect_reason") || null,
    shoreMode: flow.get("shore_mode") || "off",
    chargerMode: flow.get("charger_mode") || "off",
    vebusState: flow.get("sensor_vebus_state")
};

// Only evaluate on timer tick
if (msg.topic !== "timer") {
    return null;
}

// Freeze both state machines if VE.Bus is in VEConfigure mode (250) or unavailable
const vebusState = flow.get("sensor_vebus_state");
if (vebusState === 250 || vebusState === null || vebusState === undefined) {
    dashboard.vebusState = vebusState;
    node.status({fill: "red", shape: "ring", text: "FROZEN — VE.Bus " + (vebusState === 250 ? "VEConfigure" : "unavailable")});
    return [null, null, { payload: dashboard }];
}

// === SHORE STATE MACHINE ===
let shoreOut = null;
if (!shoreEnabled) {
    flow.set("state", "SHORE_OFF");
} else {
    if ((now - lastShoreChange) >= 30000) {
        if (shoreState === "SHORE_OFF" && ((soc > 0 && soc <= thresholdLow) || (voltage > 0 && voltage <= voltageThresholdLow))) {
            shoreState = "SHORE_ON";
            flow.set("last_state_change", now);
            flow.set("connect_reason", (soc > 0 && soc <= thresholdLow) ? "soc" : "voltage");
            node.warn("Shore: SHORE_OFF -> SHORE_ON (SOC=" + soc + "%, V=" + voltage + "V)");
        } else if (shoreState === "SHORE_ON" && soc >= thresholdHigh && (voltage === 0 || voltage > voltageThresholdLow)) {
            shoreState = "SHORE_OFF";
            flow.set("last_state_change", now);
            node.warn("Shore: SHORE_ON -> SHORE_OFF (SOC=" + soc + "%, V=" + voltage + "V)");
        }
    }
    flow.set("state", shoreState);
    shoreOut = { payload: (shoreState === "SHORE_ON") ? 0 : 1 };
}

// === CHARGER STATE MACHINE ===
let relayOut = null;
if (!chargerEnabled) {
    // Don't write relay — manual mode handler controls it
} else {
    if ((now - lastChargerChange) >= 30000) {
        if (chargerState === "CHARGER_OFF" && ((soc > 0 && soc <= chargerEnableSoc) || (voltage > 0 && voltage <= voltageThresholdLow))) {
            chargerState = "CHARGER_ON";
            flow.set("last_charger_change", now);
            flow.set("charger_connect_reason", (soc > 0 && soc <= chargerEnableSoc) ? "soc" : "voltage");
            node.warn("Charger: CHARGER_OFF -> CHARGER_ON (SOC=" + soc + "%, V=" + voltage + "V)");
        } else if (chargerState === "CHARGER_ON" && soc >= chargerDisableSoc) {
            chargerState = "CHARGER_OFF";
            flow.set("last_charger_change", now);
            node.warn("Charger: CHARGER_ON -> CHARGER_OFF (SOC=" + soc + "%)");
        }
    }
    flow.set("charger_state", chargerState);
    // CHARGER_ON = charger enabled = relay open (0)
    // CHARGER_OFF = charger disabled = relay closed (1)
    relayOut = { payload: (chargerState === "CHARGER_ON") ? 0 : 1 };
}

// Update dashboard with final states
dashboard.state = shoreEnabled ? shoreState : "MANUAL";
dashboard.chargerState = chargerEnabled ? chargerState : "MANUAL";

// Status text
let statusParts = [];
if (shoreEnabled) statusParts.push("shore:" + shoreState.replace("SHORE_",""));
else statusParts.push("shore:" + (flow.get("shore_mode") || "off"));
if (chargerEnabled) statusParts.push("chgr:" + chargerState.replace("CHARGER_",""));
else statusParts.push("chgr:" + (flow.get("charger_mode") || "off"));
node.status({fill: "green", shape: "dot", text: statusParts.join(" | ") + " SOC=" + soc + "%"});

return [
    shoreOut,                   // out1: IgnoreAcIn2
    relayOut,                   // out2: Relay 1 (charger disable)
    { payload: dashboard }      // out3: Dashboard
];

initialize:
// Set defaults for missing keys only (preserve state across deploys)
// Migrate old state names
if (flow.get('state') === 'SOLAR_ONLY') flow.set('state', 'SHORE_OFF');
if (flow.get('state') === 'GRID_ASSIST') flow.set('state', 'SHORE_ON');
if (flow.get('state') === undefined) flow.set('state', 'SHORE_OFF');

// Migrate enabled -> shore_enabled
if (flow.get('enabled') !== undefined && flow.get('shore_enabled') === undefined) {
    flow.set('shore_enabled', flow.get('enabled'));
}
if (flow.get('shore_enabled') === undefined) flow.set('shore_enabled', false);
if (flow.get('shore_mode') === undefined) flow.set('shore_mode', 'off');
if (flow.get('threshold_low') === undefined) flow.set('threshold_low', 40);
if (flow.get('threshold_high') === undefined) flow.set('threshold_high', 60);
if (flow.get('voltage_threshold_low') === undefined) flow.set('voltage_threshold_low', 48.0);
if (flow.get('last_state_change') === undefined) flow.set('last_state_change', 0);

// Migrate manual_relay -> charger_mode
if (flow.get('manual_relay') !== undefined && flow.get('charger_mode') === undefined) {
    flow.set('charger_mode', flow.get('manual_relay') ? 'off' : 'on');
}
if (flow.get('charger_mode') === undefined) flow.set('charger_mode', 'off');
if (flow.get('charger_enabled') === undefined) flow.set('charger_enabled', false);
if (flow.get('charger_state') === undefined) flow.set('charger_state', 'CHARGER_ON');
if (flow.get('charger_enable_soc') === undefined) flow.set('charger_enable_soc', 25);
if (flow.get('charger_disable_soc') === undefined) flow.set('charger_disable_soc', 45);
if (flow.get('last_charger_change') === undefined) flow.set('last_charger_change', 0);
if (flow.get('charger_connect_reason') === undefined) flow.set('charger_connect_reason', null);

