    warning = '<span style="color:#F44336;font-size:14px;">&#9888; VE.Bus unavailable</span><br>';
}

if (d.shoreMode === "on") {
    statusText = "Shore connected (manual)";
    color = "#2196F3";
} else if (d.shoreMode === "off") {
    statusText = "Shore disconnected (manual)";
    color = "#9E9E9E";
} else if (d.state === "SHORE_ON" && d.connectReason === "soc") {
    statusText = "Shore connected (SOC)";
    color = "#FF9800";
} else if (d.state === "SHORE_ON" && d.connectReason === "voltage") {
    statusText = "Shore connected (voltage)";
    color = "#FF9800";
} else if (d.state === "SHORE_ON") {
    statusText = "Shore connected";
    color = "#FF9800";
} else if (d.state === "SHORE_OFF") {
    statusText = "Shore disconnected";
    color = "#4CAF50";
}
const shoreHtml = warning + (statusText
    ? '<span style="color:' + color + ';font-size:14px;">' + statusText + '</span>'
    : "");

// out9: Charger status text (HTML with color)
let chargerText = "";
let chargerColor = "#4CAF50";

if (d.chargerMode === "on") {
    chargerText = "Charger enabled (manual)";
    chargerColor = "#2196F3";
} else if (d.chargerMode === "off") {
    chargerText = "Charger disabled (manual)";
    chargerColor = "#9E9E9E";
} else if (d.chargerState === "CHARGER_ON" && d.chargerConnectReason === "soc") {
    chargerText = "Charger enabled (SOC)";
