} else if (d.chargerState === "CHARGER_ON") {
    chargerText = "Charger enabled";
    chargerColor = "#FF9800";
} else if (d.chargerState === "CHARGER_OFF") {
    chargerText = "Charger disabled";
    chargerColor = "#4CAF50";
}
const chargerHtml = '<span style="color:' + chargerColor + ';font-size:14px;">' + chargerText + '</span>';

return [
    socMsg,
    { payload: shoreHtml },
    { payload: d.acOutL1 },
    { payload: d.acOutL2 },
